@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Components.Routing

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We value your privacy and are committed to protecting your personal data.
</p>

@if (HasConsented)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted our cookie policy. Thank you!
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext?.Request.Cookies.ContainsKey("consent") is true
            && string.Equals(HttpContext.Request.Cookies["consent"], "true", StringComparison.OrdinalIgnoreCase);
    }
}

